local LXianshilibaoPlayer = LxClass("LXianshilibaoPlayer", nil)
------------------------------------------------------------------

function LXianshilibaoPlayer:LXianshilibaoPlayer()
	self._currentGiftList = {}
	self._currentGiftMap = {}

	self._currentGiftIndex = 0
	self._currentGiftGroup = nil
end

function LXianshilibaoPlayer:RefreshGiftList()
	local giftMap = gModelPopupGift:GetGiftList()

	local currentMap = self._currentGiftMap
	local currentList = self._currentGiftList

	local removeList = {}
	local time = GetTimestamp()

	local giftGroupMap = {}
	for k,v in pairs(giftMap) do
		giftGroupMap[v.ref.giftGroup] = v
	end

	local nowIndex = self._currentGiftIndex
	for k,v in ipairs(currentList) do
		local giftData = giftGroupMap[v.ref.giftGroup]
		if not giftData or (v.endTime/1000 - time) <= 0 then
			table.insert(removeList, k)
			currentMap[v.ref.giftGroup] = nil
		else
			currentList[k] = giftData
		end
	end

	--从当前删除已经废弃的 ，修正当前下标


	local bFixed = #removeList > 0
	for k = #removeList,1,-1 do
		local removeIndex = removeList[k]
		table.remove(currentList, removeIndex)
		if nowIndex > removeIndex then
			nowIndex = nowIndex - 1
		end
	end

	--找到当前index对应的id
	if bFixed then
		if nowIndex > #currentList then
			nowIndex = 1
		end
	end

	local temData = currentList[nowIndex]
	local currentId = nil
	if temData then
		currentId = temData.ref.giftGroup
	end

	--新增
	local bAdd = false
	for k,v in pairs(giftMap) do
		if not currentMap[v.ref.giftGroup] and (v.endTime/1000 - time) > 0 then
			bAdd = true
			table.insert(currentList,v)
			currentMap[v.ref.giftGroup] = v
		end
	end

	--有新增
	if bAdd then
		table.sort(currentList, function (a,b)
			local aSort = a.ref.sort
			local bSort = b.ref.sort
			if aSort ~= bSort then
				return aSort < bSort
			end
			return false
		end)
		--找出当前下标
		for k,v in ipairs(currentList) do
			if v.ref.giftGroup == currentId then
				nowIndex = k
				break
			end
		end
	end
	if not nowIndex or nowIndex == 0 then
		nowIndex = 1
	end
	if not currentId then
		local temData = currentList[nowIndex]
		if temData then
			currentId = temData.ref.giftGroup
		end
	end

	self._currentGiftIndex = nowIndex
end


function LXianshilibaoPlayer:GetCurrentGiftData()
	return self._currentGiftList[self._currentGiftIndex]
end

function LXianshilibaoPlayer:SwitchNextGiftData()
	local index = self._currentGiftIndex
	index = index + 1
	if index > #self._currentGiftList then
		index = 1
	end
	self._currentGiftIndex = index
end

function LXianshilibaoPlayer:Destroy()
	table.removeall(self)
end
------------------------------------------------------------------
return LXianshilibaoPlayer